import{_ as a,o as t,c as r,ak as i}from"./chunks/framework.D-xjpKOc.js";const p=JSON.parse('{"title":"Shimera - Technical Brief","description":"","frontmatter":{},"headers":[],"relativePath":"devdoc/technical_brief.md","filePath":"devdoc/technical_brief.md"}'),n={name:"devdoc/technical_brief.md"};function o(c,e,l,s,d,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="shimera-technical-brief" tabindex="-1">Shimera - Technical Brief <a class="header-anchor" href="#shimera-technical-brief" aria-label="Permalink to “Shimera - Technical Brief”">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>This document provides a concise overview of Shimera for partners, recruiters, and external reviewers. For implementation-level detail, see the linked documentation pages.</p><h2 id="project-overview" tabindex="-1">Project Overview <a class="header-anchor" href="#project-overview" aria-label="Permalink to “Project Overview”">​</a></h2><p>Shimera is a C++ library that unifies shader-based visual effects across multiple rendering backends (native OpenGL, SFML, and Raylib) behind a single, consistent API.</p><p>The project is developed by a team of three and is currently in <strong>active development</strong> (C++23, built with Xmake), with the OpenGL, SFML, and Raylib backends implemented.</p><h2 id="core-architecture" tabindex="-1">Core Architecture <a class="header-anchor" href="#core-architecture" aria-label="Permalink to “Core Architecture”">​</a></h2><p>Shimera is built as a layered abstraction over OpenGL:</p><ol><li><strong>Public API</strong>: a compact entry point (<code>shimera.h</code>) with static/shared export handling.</li><li><strong>Backend abstraction</strong>: <code>IBackend</code> and <code>BackendFactory</code> define creation contracts for framebuffers, textures, shaders, and post-processors; the concrete backend is selected at <strong>compile time</strong> via preprocessor define, not runtime plugin loading.</li><li><strong>Concrete backends</strong>: OpenGL, SFML, and Raylib each implement scene capture through their native mechanism (FBO, <code>RenderTexture</code>, <code>RenderTexture2D</code>), while post-processing execution stays OpenGL-driven across all of them.</li><li><strong>Effect framework</strong>: a CRTP-based fluent API (<code>ShaderEffect&lt;Derived&gt;</code>) lets effects be declared and chained (ping-pong framebuffers).</li></ol><p>Full detail: <a href="./architecture/technical_architecture.html">Architecture documentation</a></p><h2 id="technical-innovation" tabindex="-1">Technical Innovation <a class="header-anchor" href="#technical-innovation" aria-label="Permalink to “Technical Innovation”">​</a></h2><ul><li><strong>Cross-backend</strong>: Most shader libraries only work with one backend. Shimera treats SFML, Raylib, and OpenGL as different flavors of the same GL pipeline, and hides that difference from the user.</li><li><strong>Multiple-effect chaining</strong> A multiple-effect pipeline that take normally hours of manual framebuffer and texture-binding work but becomes easy with a few method calls, while still exposing low-level uniforms when you need them.</li></ul><p>Full detail: <a href="./../userdoc/why_shimera.html">Why Shimera</a></p><h2 id="demonstrated-performance" tabindex="-1">Demonstrated Performance <a class="header-anchor" href="#demonstrated-performance" aria-label="Permalink to “Demonstrated Performance”">​</a></h2><p>Measured over 5,000 frames per effect (100-frame warm-up), on a dedicated GitHub Actions self-hosted runner (Quadro RTX 5000):</p><table tabindex="0"><thead><tr><th>Backend</th><th>Average FPS (no effects)</th><th>Average FPS (typical single effect)</th></tr></thead><tbody><tr><td>Native OpenGL</td><td>25,510 fps</td><td>22,000 fps</td></tr><tr><td>Raylib</td><td>5,257 fps</td><td>5,000 – 5,400 fps</td></tr><tr><td>SFML</td><td>5,012 fps</td><td>4,400 – 5,000 fps</td></tr></tbody></table><p>Full detail: <a href="./../userdoc/performance/benchmark.html">Performance documentation</a></p><h2 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to “Roadmap”">​</a></h2><p><strong>July 2026</strong>: Right now, Shimera has a separate abstraction layer for each backend (OpenGL, SFML, Raylib). The team is testing whether this can be replaced with one generic architecture that works for any backend. The result decides which path the project follows for the rest of this development cycle:</p><ul><li><strong>Plan A (if the generic architecture works out):</strong><ul><li>August: refactor the library on a dedicated branch around the new generic architecture.</li><li>September: integrate <a href="https://shader-slang.org/" target="_blank" rel="noreferrer">Slang</a> into the workflow and migrate existing GLSL shaders to it.</li><li>October: focus on world-space shaders and materials.</li><li>November - February: consolidate the library and expand the shader catalog.</li></ul></li><li><strong>Plan B (if it doesn&#39;t pan out):</strong> keep the current backend-specific architecture as-is. <ul><li>August*: integrate Slang into the workflow and migrate existing GLSL shaders to it.</li><li>September: implement world-space shaders directly in the current library, if not already done.</li><li>October - February: same consolidation and shader-catalog work as Plan A.</li></ul></li></ul>',20)])])}const m=a(n,[["render",o]]);export{p as __pageData,m as default};
